```scala
import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
    val INF = Long.MaxValue
    val dist = Array.ofDim[Long](m.toInt, n.toInt, 2)
    for (i <- 0 until m.toInt) {
        for (j <- 0 until n.toInt) {
            dist(i)(j)(0) = INF
            dist(i)(j)(1) = INF
        }
    }
    dist(0)(0)(1) = 1
    val heap = PriorityQueue[(Long, Int, Int, Int)]()
    heap += (1, 0, 0, 1)

    while (heap.nonEmpty) {
        val (cost, i, j, parity) = heap.pop()
        if (i == m.toInt - 1 && j == n.toInt - 1) return cost
        if (cost > dist(i)(j)(parity)) {
            // Skip if the stored distance is better
        } else {
            if (parity == 1) {
                // Move right or down
                if (j + 1 < n.toInt) {
                    val new_i = i
                    val new_j = j + 1
                    val new_cost = cost + (new_i + 1) * (new_j + 1)
                    if (new_cost < dist(new_i)(new_j)(0)) {
                        dist(new_i)(new_j)(0) = new_cost
                        heap += (new_cost, new_i, new_j, 0)
                    }
                }
                if (i + 1 < m.toInt) {
                    val new_i = i + 1
                    val new_j = j
                    val new_cost = cost + (new_i + 1) * (new_j + 1)
                    if (new_cost < dist(new_i)(new_j)(0)) {
                        dist(new_i)(new_j)(0) = new_cost
                        heap += (new_cost, new_i, new_j, 0)
                    }
                }
            } else {
                // Wait
                val new_cost = cost + waitCost(i)(j)
                if (new_cost < dist(i)(j)(1)) {
                    dist(i)(j)(1) = new_cost
                    heap += (new_cost, i, j, 1)
                }
            }
        }
    }
    -1
}
